476→// ---------------------------------------------------------------------------
477→// State guard helpers
478→// ---------------------------------------------------------------------------
479→
480→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
481→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
482→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
483→
484→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
485→  return {
486→    code: "SESSION_ERROR",
487→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
488→    httpStatus: 409,
489→  };
490→}
491→
492→function sessionAborted(sessionId: string): SessionError {
493→  return {
494→    code: "SESSION_ERROR",
495→    message: `Session ${sessionId} has been aborted`,
496→    httpStatus: 409,
497→  };
498→}
