560→// ---------------------------------------------------------------------------
561→// rejectOrchestratorSession
562→// ---------------------------------------------------------------------------
563→
564→type RejectSessionInput = {
565→  surreal: Surreal;
566→  sessionId: string;
567→  feedback: string;
568→};
569→
570→export async function rejectOrchestratorSession(
571→  input: RejectSessionInput,
572→): Promise<RejectSessionResult> {
573→  const lookup = await lookupSession(input.surreal, input.sessionId);
574→  if (!lookup.ok) {
575→    return { ok: false, error: lookup.error };
576→  }
577→  const { session, record: sessionRecord, status } = lookup;
578→
579→  if (!REJECTABLE_STATUSES.has(status)) {
580→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
581→  }
582→
583→  // 1. Update session status to active (agent resumes work)
584→  await input.surreal.update(sessionRecord).merge({
585→    orchestrator_status: "active" as OrchestratorStatus,
586→    last_feedback: input.feedback,
587→  });
588→
589→  // 2. Return task to in_progress
590→  if (session.task_id) {
591→    await input.surreal.update(session.task_id).merge({
592→      status: "in_progress",
593→      updated_at: new Date(),
594→    });
595→  }
596→
597→  return {
598→    ok: true,
599→    value: {
600→      rejected: true,
601→      continuing: true,
602→    },
603→  };
604→}
