  1→/**
  2→ * Orchestrator HTTP route handlers.
  3→ *
  4→ * Pure request->response mappings that delegate to session-lifecycle functions
  5→ * injected via OrchestratorRouteDeps. No direct DB or IO access.
  6→ */
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { withRequestLogging, type RouteHandler } from "../http/request-logging";
  9→import type {
 10→  OrchestratorSessionResult,
 11→  SessionStatusResult,
 12→  AbortSessionResult,
 13→  AcceptSessionResult,
 14→  ReviewResult,
 15→  RejectSessionResult,
 16→} from "./session-lifecycle";
 17→import type { SseRegistry } from "../streaming/sse-registry";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Port: Dependencies as function signatures
 21→// ---------------------------------------------------------------------------
 22→
 23→export type OrchestratorRouteDeps = {
 24→  createSession: (
 25→    workspaceId: string,
 26→    taskId: string,
 27→    authToken: string,
 28→  ) => Promise<OrchestratorSessionResult>;
 29→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 30→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 31→  acceptSession: (
 32→    sessionId: string,
 33→    summary: string,
 34→  ) => Promise<AcceptSessionResult>;
 35→  getReview: (sessionId: string) => Promise<ReviewResult>;
 36→  rejectSession: (
 37→    sessionId: string,
 38→    feedback: string,
 39→  ) => Promise<RejectSessionResult>;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Request body parsing
 44→// ---------------------------------------------------------------------------
 45→
 46→type AssignBody = { taskId?: string };
 47→type AcceptBody = { summary?: string };
 48→type RejectBody = { feedback?: string };
 49→
 50→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
 51→  try {
 52→    return (await request.json()) as T;
 53→  } catch {
 54→    return undefined;
 55→  }
 56→}
 57→
 58→function extractAuthToken(request: Request): string {
 59→  return request.headers.get("Cookie") ?? "";
 60→}
 61→
 62→// ---------------------------------------------------------------------------
 63→// Response builders (pure)
 64→// ---------------------------------------------------------------------------
 65→
 66→function assignResponse(
 67→  workspaceId: string,
 68→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
 69→): Response {
 70→  return jsonResponse(
 71→    {
 72→      agentSessionId: value.agentSessionId,
 73→      streamId: value.streamId,
 74→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
 75→    },
 76→    200,
 77→  );
 78→}
 79→
 80→function statusResponse(
 81→  sessionId: string,
 82→  value: {
 83→    orchestratorStatus: string;
 84→    worktreeBranch?: string;
 85→    worktreePath?: string;
 86→    startedAt?: string;
 87→    lastEventAt?: string;
 88→    error?: string;
 89→  },
 90→): Response {
 91→  return jsonResponse(
 92→    {
 93→      agentSessionId: sessionId,
 94→      orchestratorStatus: value.orchestratorStatus,
 95→      ...(value.worktreeBranch ? { worktreeBranch: value.worktreeBranch } : {}),
 96→      ...(value.worktreePath ? { worktreePath: value.worktreePath } : {}),
 97→      ...(value.startedAt ? { startedAt: value.startedAt } : {}),
 98→      ...(value.lastEventAt ? { lastEventAt: value.lastEventAt } : {}),
 99→      ...(value.error ? { error: value.error } : {}),
100→    },
101→    200,
102→  );
103→}
104→
105→function acceptResponse(): Response {
106→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
107→}
108→
109→function abortResponse(): Response {
110→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
111→}
112→
113→function reviewResponse(value: {
114→  taskTitle: string;
115→  diff: unknown;
116→  session: unknown;
117→}): Response {
118→  return jsonResponse(value, 200);
119→}
120→
121→function rejectResponse(): Response {
122→  return jsonResponse({ rejected: true, continuing: true }, 200);
123→}
124→
125→function sessionErrorResponse(error: {
126→  message: string;
127→  httpStatus: number;
128→}): Response {
129→  return jsonError(error.message, error.httpStatus);
130→}
131→
132→// ---------------------------------------------------------------------------
133→// Route handler factory
134→// ---------------------------------------------------------------------------
135→
136→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
137→  const assign: RouteHandler = async (request) => {
138→    const workspaceId = request.params.workspaceId;
139→    const body = await parseJsonBody<AssignBody>(request);
140→
141→    if (!body?.taskId) {
142→      return jsonError("taskId is required", 400);
143→    }
144→
145→    const authToken = extractAuthToken(request);
146→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
147→
148→    if (!result.ok) {
149→      return sessionErrorResponse(result.error);
150→    }
151→
152→    return assignResponse(workspaceId, result.value);
153→  };
154→
155→  const status: RouteHandler = async (request) => {
156→    const sessionId = request.params.sessionId;
157→    const result = await deps.getSessionStatus(sessionId);
158→
159→    if (!result.ok) {
160→      return sessionErrorResponse(result.error);
161→    }
162→
163→    return statusResponse(sessionId, result.value);
164→  };
165→
166→  const accept: RouteHandler = async (request) => {
167→    const sessionId = request.params.sessionId;
168→    const body = await parseJsonBody<AcceptBody>(request);
169→    const summary = body?.summary ?? "";
170→
171→    const result = await deps.acceptSession(sessionId, summary);
172→
173→    if (!result.ok) {
174→      return sessionErrorResponse(result.error);
175→    }
176→
177→    return acceptResponse();
178→  };
179→
180→  const abort: RouteHandler = async (request) => {
181→    const sessionId = request.params.sessionId;
182→    const result = await deps.abortSession(sessionId);
183→
184→    if (!result.ok) {
185→      return sessionErrorResponse(result.error);
186→    }
187→
188→    return abortResponse();
189→  };
190→
191→  const review: RouteHandler = async (request) => {
192→    const sessionId = request.params.sessionId;
193→    const result = await deps.getReview(sessionId);
194→
195→    if (!result.ok) {
196→      return sessionErrorResponse(result.error);
197→    }
198→
199→    return reviewResponse(result.value);
200→  };
201→
202→  const reject: RouteHandler = async (request) => {
203→    const sessionId = request.params.sessionId;
204→    const body = await parseJsonBody<RejectBody>(request);
205→
206→    if (!body?.feedback || body.feedback.trim() === "") {
207→      return jsonError("feedback is required", 400);
208→    }
209→
210→    const result = await deps.rejectSession(sessionId, body.feedback);
211→
212→    if (!result.ok) {
213→      return sessionErrorResponse(result.error);
214→    }
215→
216→    return rejectResponse();
217→  };
218→
219→  return { assign, status, accept, abort, review, reject };
220→}
