244→// ---------------------------------------------------------------------------
245→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
246→// ---------------------------------------------------------------------------
247→
248→export type OrchestratorWiringDeps = {
249→  surreal: import("surrealdb").Surreal;
250→  shellExec: import("./worktree-manager").ShellExec;
251→  brainBaseUrl: string;
252→  sseRegistry?: SseRegistry;
253→};
254→
255→export function wireOrchestratorRoutes(
256→  wiringDeps: OrchestratorWiringDeps,
257→): {
258→  assign: RouteHandler;
259→  status: RouteHandler;
260→  accept: RouteHandler;
261→  abort: RouteHandler;
262→  review: RouteHandler;
263→  reject: RouteHandler;
264→  stream?: RouteHandler;
265→} {
266→  // Lazy imports to keep module boundary clean
267→  const lifecycleImport = import("./session-lifecycle");
268→  const queriesImport = import("../mcp/mcp-queries");
269→  const guardImport = import("./assignment-guard");
270→
271→  // Helper: resolve repo_path from workspace record
272→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
273→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
274→      `SELECT repo_path FROM $ws;`,
275→      { ws: workspaceRecord },
276→    );
277→    const repoPath = rows[0]?.repo_path;
278→    if (!repoPath) {
279→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
280→    }
281→    return repoPath;
282→  };
283→
284→  // Use mock spawn for acceptance tests, production spawn otherwise
285→  const spawnOpenCodeImport = process.env.ORCHESTRATOR_MOCK_OPENCODE === "true"
286→    ? Promise.resolve({
287→        spawnOpenCode: async () => ({
288→          sessionId: crypto.randomUUID(),
289→          abort: () => {},
290→          sendPrompt: async () => {},
291→          eventStream: (async function* () {})(),
292→        }),
293→      })
294→    : import("./spawn-opencode");
295→
296→  const routeDeps: OrchestratorRouteDeps = {
297→    createSession: async (workspaceId, taskId, authToken) => {
298→      const [lifecycle, queries, guard, { spawnOpenCode }] = await Promise.all([
299→        lifecycleImport,
300→        queriesImport,
301→        guardImport,
302→        spawnOpenCodeImport,
303→      ]);
304→      return lifecycle.createOrchestratorSession({
305→        surreal: wiringDeps.surreal,
306→        shellExec: wiringDeps.shellExec,
307→        brainBaseUrl: wiringDeps.brainBaseUrl,
308→        workspaceId,
309→        taskId,
310→        authToken,
311→        validateAssignment: guard.validateAssignment,
312→        createAgentSession: queries.createAgentSession,
313→        spawnOpenCode,
314→      });
315→    },
316→
317→    getSessionStatus: async (sessionId) => {
318→      const lifecycle = await lifecycleImport;
319→      return lifecycle.getOrchestratorSessionStatus({
320→        surreal: wiringDeps.surreal,
321→        sessionId,
322→      });
323→    },
324→
325→    abortSession: async (sessionId) => {
326→      const [lifecycle, queries] = await Promise.all([
327→        lifecycleImport,
328→        queriesImport,
329→      ]);
330→      return lifecycle.abortOrchestratorSession({
331→        surreal: wiringDeps.surreal,
332→        shellExec: wiringDeps.shellExec,
333→        resolveRepoRoot,
334→        sessionId,
335→        endAgentSession: queries.endAgentSession,
336→      });
337→    },
338→
339→    acceptSession: async (sessionId, summary) => {
340→      const [lifecycle, queries] = await Promise.all([
341→        lifecycleImport,
342→        queriesImport,
343→      ]);
344→      return lifecycle.acceptOrchestratorSession({
345→        surreal: wiringDeps.surreal,
346→        sessionId,
347→        summary,
348→        endAgentSession: queries.endAgentSession,
349→      });
350→    },
351→
352→    getReview: async (sessionId) => {
353→      const [lifecycle, worktreeManager] = await Promise.all([
354→        lifecycleImport,
355→        import("./worktree-manager"),
356→      ]);
357→      return lifecycle.getOrchestratorReview({
358→        surreal: wiringDeps.surreal,
359→        sessionId,
360→        resolveRepoRoot,
361→        getDiff: (repoRoot: string, branchName: string) =>
362→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
363→        getTaskTitle: async (taskId: string) => {
364→          const { RecordId } = await import("surrealdb");
365→          const taskRecord = new RecordId("task", taskId);
366→          const rows = (await wiringDeps.surreal.query(
367→            `SELECT title FROM $task;`,
368→            { task: taskRecord },
369→          )) as Array<Array<{ title: string }>>;
370→          return rows[0]?.[0]?.title ?? "";
371→        },
372→      });
373→    },
374→
375→    rejectSession: async (sessionId, feedback) => {
376→      const lifecycle = await lifecycleImport;
377→      return lifecycle.rejectOrchestratorSession({
378→        surreal: wiringDeps.surreal,
379→        sessionId,
380→        feedback,
381→      });
382→    },
383→  };
384→
385→  const handlers = createOrchestratorRouteHandlers(routeDeps);
386→
387→  const streamHandler = wiringDeps.sseRegistry
388→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
389→    : undefined;
390→
391→  return {
392→    assign: withRequestLogging("orchestrator.assign", "POST", handlers.assign),
393→    status: withRequestLogging("orchestrator.status", "GET", handlers.status),
394→    accept: withRequestLogging("orchestrator.accept", "POST", handlers.accept),
395→    abort: withRequestLogging("orchestrator.abort", "POST", handlers.abort),
396→    review: withRequestLogging("orchestrator.review", "GET", handlers.review),
397→    reject: withRequestLogging("orchestrator.reject", "POST", handlers.reject),
398→    ...(streamHandler
399→      ? { stream: withRequestLogging("orchestrator.stream", "GET", streamHandler.stream) }
400→      : {}),
401→  };
402→}
