  1→/**
  2→ * AgentStatusSection -- shows agent assignment and live status for tasks.
  3→ *
  4→ * Pure core: deriveAgentStatusView computes what to render from entity + session data.
  5→ * Effect boundary: the component wires useAgentSession for SSE updates and assignAgent for dispatch.
  6→ */
  7→
  8→import { useState } from "react";
  9→import type { AgentSessionSummary, EntityKind } from "../../../shared/contracts";
 10→import { useAgentSession, type AgentSessionStatus } from "../../hooks/use-agent-session";
 11→import { assignAgent, type AssignAgentResponse } from "../../graph/orchestrator-api";
 12→import { useWorkspaceState } from "../../stores/workspace-state";
 13→
 14→// ---------------------------------------------------------------------------
 15→// Pure core: view derivation
 16→// ---------------------------------------------------------------------------
 17→
 18→const ASSIGNABLE_STATUSES = new Set(["ready", "todo"]);
 19→
 20→export type AgentStatusViewHidden = { variant: "hidden" };
 21→export type AgentStatusViewAssign = { variant: "assign" };
 22→export type AgentStatusViewActive = {
 23→  variant: "active";
 24→  agentSessionId: string;
 25→  orchestratorStatus: string;
 26→  filesChangedCount: number;
 27→  streamUrl: string;
 28→  startedAt: string;
 29→};
 30→
 31→export type AgentStatusView =
 32→  | AgentStatusViewHidden
 33→  | AgentStatusViewAssign
 34→  | AgentStatusViewActive;
 35→
 36→export type DeriveAgentStatusInput = {
 37→  entityKind: string;
 38→  entityStatus: string;
 39→  agentSession?: AgentSessionSummary;
 40→};
 41→
 42→export function deriveAgentStatusView(input: DeriveAgentStatusInput): AgentStatusView {
 43→  if (input.entityKind !== "task") {
 44→    return { variant: "hidden" };
 45→  }
 46→
 47→  if (input.agentSession) {
 48→    return {
 49→      variant: "active",
 50→      agentSessionId: input.agentSession.agentSessionId,
 51→      orchestratorStatus: input.agentSession.orchestratorStatus,
 52→      filesChangedCount: input.agentSession.filesChangedCount,
 53→      streamUrl: `/api/orchestrator/stream/${encodeURIComponent(input.agentSession.streamId)}`,
 54→      startedAt: input.agentSession.startedAt,
 55→    };
 56→  }
 57→
 58→  if (ASSIGNABLE_STATUSES.has(input.entityStatus)) {
 59→    return { variant: "assign" };
 60→  }
 61→
 62→  return { variant: "hidden" };
 63→}
 64→
 65→// ---------------------------------------------------------------------------
 66→// Status badge display
 67→// ---------------------------------------------------------------------------
 68→
 69→const STATUS_LABELS: Record<AgentSessionStatus, string> = {
 70→  spawning: "Spawning",
 71→  active: "Working",
 72→  idle: "Idle",
 73→  completed: "Completed",
 74→  aborted: "Aborted",
 75→  error: "Error",
 76→};
 77→
 78→function statusLabel(status: AgentSessionStatus): string {
 79→  return STATUS_LABELS[status];
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Component
 84→// ---------------------------------------------------------------------------
 85→
 86→export function AgentStatusSection({
 87→  entityId,
 88→  workspaceId,
 89→  entityKind,
 90→  entityStatus,
 91→  agentSession,
 92→}: {
 93→  entityId: string;
 94→  workspaceId: string;
 95→  entityKind: EntityKind;
 96→  entityStatus: string;
 97→  agentSession?: AgentSessionSummary;
 98→}) {
 99→  const repoPath = useWorkspaceState((s) => s.repoPath);
100→  const setStoreRepoPath = useWorkspaceState((s) => s.setRepoPath);
101→  const [assigning, setAssigning] = useState(false);
102→  const [assignError, setAssignError] = useState<string | undefined>();
103→  const [assignResult, setAssignResult] = useState<AssignAgentResponse | undefined>();
104→  const [repoPathInput, setRepoPathInput] = useState("");
105→  const [settingRepoPath, setSettingRepoPath] = useState(false);
106→  const [repoPathError, setRepoPathError] = useState<string | undefined>();
107→
108→  // Derive the initial view from props
109→  const initialView = deriveAgentStatusView({ entityKind, entityStatus, agentSession });
110→
111→  // If we have an assign result, use its stream URL; otherwise use session from props.
112→  // streamUrl is a dependency of useAgentSession's useEffect, so when assignResult
113→  // arrives and triggers a re-render, the hook will start the SSE subscription.
114→  const streamUrl = assignResult?.streamUrl ?? (initialView.variant === "active" ? initialView.streamUrl : undefined);
115→  const startedAt = initialView.variant === "active" ? initialView.startedAt : new Date().toISOString();
116→
117→  // SSE subscription -- only active when we have a stream URL
118→  const { state: sessionState } = useAgentSession(streamUrl, startedAt);
119→
120→  // Determine what to show
121→  const hasActiveStream = streamUrl !== undefined;
122→
123→  if (initialView.variant === "hidden" && !hasActiveStream) {
124→    return undefined;
125→  }
126→
127→  async function handleAssign() {
128→    if (assigning) return;
129→    setAssigning(true);
130→    setAssignError(undefined);
131→    try {
132→      const rawTaskId = entityId.includes(":") ? entityId.split(":")[1] : entityId;
133→      const result = await assignAgent(workspaceId, rawTaskId);
134→      setAssignResult(result);
135→    } catch (err) {
136→      setAssignError(err instanceof Error ? err.message : "Failed to assign agent");
137→    } finally {
138→      setAssigning(false);
139→    }
140→  }
141→
142→  // Show active session view (either from props or from fresh assignment)
143→  if (hasActiveStream) {
144→    const displayStatus = sessionState.status;
145→    const displayFiles = initialView.variant === "active"
146→      ? initialView.filesChangedCount + sessionState.filesChanged
147→      : sessionState.filesChanged;
148→
149→    return (
150→      <div className="entity-detail-section agent-status-section">
151→        <h4>Agent</h4>
152→        <div className="agent-status-row">
153→          <span className={`agent-status-badge agent-status-${displayStatus}`} data-testid="agent-status-badge">
154→            {statusLabel(displayStatus)}
155→          </span>
156→          {displayFiles > 0 ? (
157→            <span className="agent-file-count" data-testid="agent-file-count">
158→              {displayFiles} file{displayFiles !== 1 ? "s" : ""} changed
159→            </span>
160→          ) : undefined}
161→        </div>
162→        {sessionState.stallWarning ? (
163→          <p className="agent-stall-warning" data-testid="agent-stall-warning">
164→            Agent may be stalled (no activity for {sessionState.stallWarning.stallDurationSeconds}s)
165→          </p>
166→        ) : undefined}
167→        {sessionState.connectionError ? (
168→          <p className="agent-connection-error">{sessionState.connectionError}</p>
169→        ) : undefined}
170→        {displayStatus === "idle" ? (
171→          <a
172→            className="agent-review-link"
173→            data-testid="agent-review-link"
174→            href={`/review/${encodeURIComponent(
175→              assignResult?.agentSessionId
176→                ?? (initialView.variant === "active" ? initialView.agentSessionId : ""),
177→            )}`}
178→          >
179→            Review
180→          </a>
181→        ) : undefined}
182→      </div>
183→    );
184→  }
185→
186→  // Show assign button (with missing repo_path banner when applicable)
187→  if (initialView.variant === "assign") {
188→    const missingRepoPath = repoPath === undefined;
189→
190→    return (
191→      <div className="entity-detail-section agent-status-section">
192→        <h4>Agent</h4>
193→        {missingRepoPath ? (
194→          <div className="agent-repo-path-banner" data-testid="agent-repo-path-banner">
195→            <p>Repository path is not configured for this workspace. Set it before assigning an agent.</p>
196→            <form
197→              className="agent-repo-path-form"
198→              data-testid="agent-repo-path-form"
199→              onSubmit={async (e) => {
200→                e.preventDefault();
201→                const trimmed = repoPathInput.trim();
202→                if (!trimmed || settingRepoPath) return;
203→                setSettingRepoPath(true);
204→                setRepoPathError(undefined);
205→                try {
206→                  const res = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/repo-path`, {
207→                    method: "POST",
208→                    headers: { "Content-Type": "application/json" },
209→                    body: JSON.stringify({ path: trimmed }),
210→                  });
211→                  if (!res.ok) {
212→                    const body = await res.json().catch(() => ({ error: "Failed to set repository path" }));
213→                    setRepoPathError(body.error ?? "Failed to set repository path");
214→                    return;
215→                  }
216→                  setStoreRepoPath(trimmed);
217→                  setRepoPathInput("");
218→                } catch {
219→                  setRepoPathError("Network error");
220→                } finally {
221→                  setSettingRepoPath(false);
222→                }
223→              }}
224→            >
225→              <input
226→                type="text"
227→                className="agent-repo-path-input"
228→                data-testid="agent-repo-path-input"
229→                placeholder="/path/to/git/repository"
230→                value={repoPathInput}
231→                onChange={(e) => setRepoPathInput(e.target.value)}
232→                disabled={settingRepoPath}
233→              />
234→              <button
235→                type="submit"
236→                className="agent-repo-path-action"
237→                data-testid="agent-repo-path-action"
238→                disabled={settingRepoPath || repoPathInput.trim().length === 0}
239→              >
240→                {settingRepoPath ? "Setting..." : "Set Path"}
241→              </button>
242→            </form>
243→            {repoPathError ? (
244→              <p className="agent-repo-path-error" data-testid="agent-repo-path-error">{repoPathError}</p>
245→            ) : undefined}
246→          </div>
247→        ) : undefined}
248→        <button
249→          type="button"
250→          className="agent-assign-button"
251→          data-testid="agent-assign-button"
252→          disabled={assigning || missingRepoPath}
253→          onClick={handleAssign}
254→        >
255→          {assigning ? "Assigning..." : "Assign Agent"}
256→        </button>
257→        {assignError ? (
258→          <p className="agent-assign-error" data-testid="agent-assign-error">{assignError}</p>
259→        ) : undefined}
260→      </div>
261→    );
262→  }
263→
264→  return undefined;
265→}
