  6→// ---------------------------------------------------------------------------
  7→// Port allocation — find a free port by binding to 0
  8→// ---------------------------------------------------------------------------
  9→
 10→async function findFreePort(): Promise<number> {
 11→  const { createServer } = await import("node:net");
 12→  return new Promise((resolve, reject) => {
 13→    const srv = createServer();
 14→    srv.listen(0, "127.0.0.1", () => {
 15→      const addr = srv.address();
 16→      if (!addr || typeof addr === "string") {
 17→        srv.close();
 18→        reject(new Error("Failed to allocate port"));
 19→        return;
 20→      }
 21→      const port = addr.port;
 22→      srv.close(() => resolve(port));
 23→    });
 24→    srv.on("error", reject);
 25→  });
 26→}
