 97→          (request) => workspaceHandlers.handleWorkspaceSidebar(request.params.workspaceId),
 98→        ),
 99→      },
100→      "/api/workspaces/:workspaceId/repo-path": {
101→        POST: withRequestLogging(
102→          "POST /api/workspaces/:workspaceId/repo-path",
103→          "POST",
104→          (request) => workspaceHandlers.handleUpdateRepoPath(request.params.workspaceId, request),
105→        ),
106→      },
