 64→      additions: number;
 65→      deletions: number;
 66→    }>;
 67→    rawDiff: string;
 68→    stats: {
 69→      filesChanged: number;
 70→      insertions: number;
 71→      deletions: number;
 72→    };
 73→  };
 74→  session: {
