 84→// ---------------------------------------------------------------------------
 85→// Infrastructure Setup
 86→// ---------------------------------------------------------------------------
 87→
 88→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 89→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 90→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 91→const portBase = Number(process.env.SMOKE_PORT_BASE ?? "3200");
 92→
 93→export function setupOrchestratorSuite(
 94→  suiteName: string,
 95→): () => OrchestratorTestRuntime {
 96→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 97→  const namespace = `orch_${runId}`;
 98→  const suiteSlug = suiteName
 99→    .toLowerCase()
100→    .replace(/[^a-z0-9]+/g, "_")
101→    .replace(/^_+|_+$/g, "");
102→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
103→
104→  let runtime: OrchestratorTestRuntime | undefined;
105→  let serverProcess: ReturnType<typeof Bun.spawn> | undefined;
106→  let setupSucceeded = false;
107→
108→  beforeAll(async () => {
109→    const port = portBase + Math.floor(Math.random() * 20000);
110→    const baseUrl = `http://127.0.0.1:${port}`;
111→
112→    const surreal = new Surreal();
113→    await withTimeout(
114→      () => surreal.connect(surrealUrl),
115→      10_000,
116→      "connect to SurrealDB",
117→    );
118→    await withTimeout(
119→      () =>
120→        surreal.signin({
121→          username: surrealUsername,
122→          password: surrealPassword,
123→        }),
124→      10_000,
125→      "authenticate with SurrealDB",
126→    );
127→
128→    await withTimeout(
129→      () => surreal.query(`DEFINE NAMESPACE ${namespace};`),
130→      10_000,
131→      "define test namespace",
132→    );
133→    await withTimeout(
134→      () => surreal.use({ namespace }),
135→      10_000,
136→      "switch to test namespace",
137→    );
138→    await withTimeout(
139→      () => surreal.query(`DEFINE DATABASE ${database};`),
140→      10_000,
141→      "define test database",
142→    );
143→    await withTimeout(
144→      () => surreal.use({ namespace, database }),
145→      10_000,
146→      "switch to test namespace/database",
147→    );
148→
149→    const schemaSql = readFileSync(
150→      join(process.cwd(), "schema", "surreal-schema.surql"),
151→      "utf8",
152→    );
153→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
154→
155→    serverProcess = Bun.spawn(["bun", "run", "app/server.ts"], {
156→      cwd: process.cwd(),
157→      env: {
158→        ...process.env,
159→        PORT: String(port),
160→        SURREAL_NAMESPACE: namespace,
161→        SURREAL_DATABASE: database,
162→        BETTER_AUTH_URL: baseUrl,
163→        BETTER_AUTH_SECRET:
164→          process.env.BETTER_AUTH_SECRET ??
165→          "smoke-test-secret-at-least-32-chars-long",
166→        GITHUB_CLIENT_ID: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
167→        GITHUB_CLIENT_SECRET:
168→          process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
169→        // Orchestrator-specific: disable real OpenCode spawning in tests
170→        ORCHESTRATOR_MOCK_OPENCODE: "true",
171→      },
172→      stdout: "pipe",
173→      stderr: "inherit",
174→    });
175→
176→    await waitForHealth(baseUrl, serverProcess, 15_000);
177→    runtime = { baseUrl, surreal, namespace, database, port };
178→    setupSucceeded = true;
179→  }, 60_000);
180→
181→  afterAll(async () => {
182→    if (serverProcess) {
183→      serverProcess.kill();
184→      await serverProcess.exited;
185→    }
186→
187→    if (!runtime) return;
188→
189→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
190→      try {
191→        await withTimeout(
192→          () => runtime!.surreal.query(`REMOVE DATABASE ${database};`),
193→          10_000,
194→          "remove test database",
195→        );
196→      } catch {
197→        // Best effort cleanup.
198→      }
199→
200→      try {
201→        await withTimeout(
202→          () => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`),
203→          10_000,
204→          "remove test namespace",
205→        );
206→      } catch {
207→        // Best effort cleanup.
208→      }
209→    }
210→
211→    await withTimeout(
212→      () => runtime!.surreal.close(),
213→      2_000,
214→      "close SurrealDB",
215→    ).catch(() => undefined);
216→  }, 20_000);
217→
218→  return () => {
219→    if (!runtime) {
220→      throw new Error(
221→        "Orchestrator runtime requested before suite setup completed",
222→      );
223→    }
224→    return runtime;
225→  };
226→}
