543→async function waitForHealth(
544→  url: string,
545→  process: ReturnType<typeof Bun.spawn>,
546→  timeoutMs: number,
547→): Promise<void> {
548→  const start = Date.now();
549→  while (Date.now() - start < timeoutMs) {
550→    if (typeof process.exitCode === "number") {
551→      const stderr = process.stderr
552→        ? await new Response(process.stderr).text()
553→        : "";
554→      throw new Error(
555→        `Server exited early with code ${process.exitCode}\n${stderr}`,
556→      );
557→    }
558→    try {
559→      const response = await fetch(`${url}/healthz`);
560→      if (response.ok) return;
561→    } catch {
562→      // Keep polling.
563→    }
564→    await Bun.sleep(200);
565→  }
566→  throw new Error(`Timed out waiting for server health at ${url}/healthz`);
567→}
568→
569→async function withTimeout<T>(
570→  callback: () => Promise<T>,
571→  timeoutMs: number,
572→  label: string,
573→): Promise<T> {
574→  return await Promise.race([
575→    callback(),
576→    new Promise<T>((_, reject) => {
577→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
578→    }),
579→  ]);
580→}
