  1→/**
  2→ * Event Bridge: Agent Events Forwarded to User via SSE
  3→ *
  4→ * Traces: US-1.1 (stream agent events to UI)
  5→ *
  6→ * Validates that activity from the coding agent (file changes, tool calls,
  7→ * errors) is forwarded to the user's browser through the Brain SSE stream.
  8→ * The Event Bridge transforms OpenCode-native events into Brain stream events.
  9→ *
 10→ * Driving ports: GET /api/orchestrator/stream/:streamId (SSE)
 11→ *                POST /api/orchestrator/:ws/assign (triggers event bridge)
 12→ */
 13→import { describe, expect, it } from "bun:test";
 14→import {
 15→  setupOrchestratorSuite,
 16→  createTestUser,
 17→  createTestWorkspace,
 18→  createReadyTask,
 19→  assignTaskToAgent,
 20→} from "./orchestrator-test-kit";
 21→
 22→const getRuntime = setupOrchestratorSuite("event_bridge");
 23→
 24→type AgentStreamEvent = {
 25→  type: string;
 26→  sessionId?: string;
 27→  file?: string;
 28→  changeType?: string;
 29→  token?: string;
 30→  error?: string;
 31→};
 32→
 33→/**
 34→ * Collects SSE events from the agent stream until timeout or done event.
 35→ */
 36→async function collectAgentEvents(
 37→  streamUrl: string,
 38→  timeoutMs: number,
 39→): Promise<AgentStreamEvent[]> {
 40→  const response = await fetch(streamUrl, {
 41→    headers: { Accept: "text/event-stream" },
 42→  });
 43→  if (!response.ok || !response.body) {
 44→    throw new Error(`Failed to open agent SSE stream (${response.status})`);
 45→  }
 46→
 47→  const reader = response.body.getReader();
 48→  const decoder = new TextDecoder();
 49→  const events: AgentStreamEvent[] = [];
 50→  let buffer = "";
 51→
 52→  const timeout = setTimeout(() => {
 53→    void reader.cancel();
 54→  }, timeoutMs);
 55→
 56→  try {
 57→    while (true) {
 58→      const { value, done } = await reader.read();
 59→      if (done) break;
 60→
 61→      buffer += decoder.decode(value, { stream: true });
 62→      const segments = buffer.split("\n\n");
 63→      buffer = segments.pop() ?? "";
 64→
 65→      for (const segment of segments) {
 66→        const dataLine = segment
 67→          .split("\n")
 68→          .find((line) => line.startsWith("data: "));
 69→        if (!dataLine) continue;
 70→
 71→        const event = JSON.parse(
 72→          dataLine.slice("data: ".length),
 73→        ) as AgentStreamEvent;
 74→        events.push(event);
 75→
 76→        if (event.type === "agent_done" || event.type === "agent_error") {
 77→          return events;
 78→        }
 79→      }
 80→    }
 81→  } finally {
 82→    clearTimeout(timeout);
 83→    reader.releaseLock();
 84→  }
 85→
 86→  return events;
 87→}
