154→  it("rejects a second agent assignment while first agent is still working", async () => {
155→    const { baseUrl, surreal } = getRuntime();
156→
157→    // Given a task that already has an active agent working on it
158→    const user = await createTestUser(baseUrl, "guard-dup");
