183→// ---------------------------------------------------------------------------
184→// createOrchestratorSession
185→// ---------------------------------------------------------------------------
186→
187→type CreateSessionInput = {
188→  surreal: Surreal;
189→  shellExec: ShellExec;
190→  brainBaseUrl: string;
191→  workspaceId: string;
192→  taskId: string;
193→  authToken: string;
194→  spawnOpenCode?: SpawnOpenCodeFn;
195→  validateAssignment: (
196→    surreal: Surreal,
197→    workspaceId: string,
198→    taskId: string,
199→  ) => Promise<AssignmentResult>;
200→  createAgentSession: (input: {
201→    surreal: Surreal;
202→    agent: string;
203→    workspaceRecord: RecordId<"workspace", string>;
204→    taskId?: string;
205→  }) => Promise<{ session_id: string }>;
206→};
207→
208→export async function createOrchestratorSession(
209→  input: CreateSessionInput,
210→): Promise<OrchestratorSessionResult> {
211→  // 1. Validate assignment eligibility
212→  const assignmentResult = await input.validateAssignment(
213→    input.surreal,
214→    input.workspaceId,
215→    input.taskId,
216→  );
217→
218→  if (!assignmentResult.ok) {
219→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
220→  }
221→
222→  const { validation } = assignmentResult;
223→  const taskSlug = slugFromTitle(validation.title);
224→  const repoRoot = validation.repoPath;
225→
226→  // 2. Create worktree
227→  const worktreeResult = await createWorktree(
228→    input.shellExec,
229→    repoRoot,
230→    taskSlug,
231→  );
232→
233→  if (!worktreeResult.ok) {
234→    return {
235→      ok: false,
236→      error: worktreeError(worktreeResult.error.message),
237→    };
238→  }
239→
240→  const { branchName, worktreePath } = worktreeResult.value;
241→
242→  // 3. Create agent_session record
243→  const { session_id: agentSessionId } = await input.createAgentSession({
244→    surreal: input.surreal,
245→    agent: "opencode",
246→    workspaceRecord: validation.workspaceRecord,
247→    taskId: input.taskId,
248→  });
249→
250→  const streamId = generateStreamId(agentSessionId);
251→
252→  // 4. Build config and spawn OpenCode
253→  const config = buildOpencodeConfig({
254→    brainBaseUrl: input.brainBaseUrl,
255→    workspaceId: input.workspaceId,
256→    authToken: input.authToken,
257→  });
258→
259→  const spawnFn = input.spawnOpenCode ?? defaultSpawnOpenCode;
260→  let handle: OpenCodeHandle;
261→  try {
262→    handle = await spawnFn(config, worktreePath, input.taskId);
263→  } catch (err) {
264→    // Rollback: remove worktree and delete agent_session on spawn failure
265→    await removeWorktree(input.shellExec, repoRoot, branchName);
266→    const sessionRecord = new RecordId("agent_session", agentSessionId);
267→    await input.surreal.delete(sessionRecord);
268→    return {
269→      ok: false,
270→      error: worktreeError(`Failed to spawn OpenCode: ${err instanceof Error ? err.message : String(err)}`),
271→    };
272→  }
273→
274→  // 5. Register handle for later abort
275→  handleRegistry.set(agentSessionId, handle);
276→
277→  // 6. Update agent_session with orchestrator fields
278→  const sessionRecord = new RecordId("agent_session", agentSessionId);
279→  await input.surreal.update(sessionRecord).merge({
280→    orchestrator_status: "spawning" as OrchestratorStatus,
281→    worktree_branch: branchName,
282→    worktree_path: worktreePath,
283→    opencode_session_id: handle.sessionId,
284→    stream_id: streamId,
285→  });
286→
287→  return {
288→    ok: true,
289→    value: {
290→      agentSessionId,
291→      streamId,
292→      worktreeBranch: branchName,
293→    },
294→  };
295→}
296→
297→// Default spawn -- placeholder for production use
298→async function defaultSpawnOpenCode(
299→  _config: OpencodeConfig,
300→  _worktreePath: string,
301→  _taskId: string,
302→): Promise<OpenCodeHandle> {
303→  throw new Error(
304→    "spawnOpenCode not provided -- must be injected for production use",
305→  );
306→}
