308→// ---------------------------------------------------------------------------
309→// getOrchestratorSessionStatus
310→// ---------------------------------------------------------------------------
311→
312→type GetStatusInput = {
313→  surreal: Surreal;
314→  sessionId: string;
315→};
316→
317→export async function getOrchestratorSessionStatus(
318→  input: GetStatusInput,
319→): Promise<SessionStatusResult> {
320→  const lookup = await lookupSession(input.surreal, input.sessionId);
321→  if (!lookup.ok) {
322→    return { ok: false, error: lookup.error };
323→  }
324→  const { session } = lookup;
325→
326→  return {
327→    ok: true,
328→    value: {
329→      orchestratorStatus: lookup.status,
330→      ...(session.worktree_branch ? { worktreeBranch: session.worktree_branch } : {}),
331→      ...(session.worktree_path ? { worktreePath: session.worktree_path } : {}),
332→      ...(session.started_at ? { startedAt: session.started_at } : {}),
333→      ...(session.last_event_at ? { lastEventAt: session.last_event_at } : {}),
334→      ...(session.error ? { error: session.error } : {}),
335→    },
336→  };
337→}
