  1→/**
  2→ * Event bridge: transforms OpenCode SSE events into Brain StreamEvent variants
  3→ * and forwards them to the SSE registry.
  4→ *
  5→ * Pure transform function (transformOpencodeEvent) + effectful bridge handle
  6→ * (startEventBridge) that manages the event forwarding lifecycle.
  7→ */
  8→import type {
  9→  AgentTokenEvent,
 10→  AgentFileChangeEvent,
 11→  AgentStatusEvent,
 12→  StreamEvent,
 13→} from "../../shared/contracts";
 14→import type { StallDetectorHandle } from "./stall-detector";
 15→
 16→// ---------------------------------------------------------------------------
 17→// OpenCode event types (from @opencode-ai/sdk)
 18→// ---------------------------------------------------------------------------
 19→
 20→export type OpencodeEvent =
 21→  | { type: "message.part.updated"; sessionId: string; part: { type: "text"; content: string } }
 22→  | { type: "file.edited"; sessionId: string; file: string }
 23→  | { type: "session.updated"; sessionId: string; status: string }
 24→  | { type: "session.error"; sessionId: string; error: string };
 25→
 26→// ---------------------------------------------------------------------------
 27→// Port: dependencies as function signatures
 28→// ---------------------------------------------------------------------------
 29→
 30→export type EventBridgeDeps = {
 31→  emitEvent: (streamId: string, event: StreamEvent) => void;
 32→  updateLastEventAt: (sessionId: string) => Promise<void>;
 33→};
 34→
 35→// ---------------------------------------------------------------------------
 36→// Bridge handle
 37→// ---------------------------------------------------------------------------
 38→
 39→export type EventBridgeHandle = {
 40→  handleEvent: (event: OpencodeEvent) => void;
 41→  stop: () => void;
 42→};
 43→
 44→// ---------------------------------------------------------------------------
 45→// Pure transform: OpenCode event -> Brain StreamEvent
 46→// ---------------------------------------------------------------------------
 47→
 48→const STATUS_MAP: Record<string, AgentStatusEvent["status"]> = {
 49→  busy: "active",
 50→  running: "active",
 51→  idle: "idle",
 52→  completed: "completed",
 53→  done: "completed",
 54→  error: "error",
 55→  failed: "error",
 56→  aborted: "aborted",
 57→  cancelled: "aborted",
 58→};
 59→
 60→function mapOpencodeStatus(opencodeStatus: string): AgentStatusEvent["status"] {
 61→  return STATUS_MAP[opencodeStatus] ?? "active";
 62→}
 63→
 64→export function transformOpencodeEvent(
 65→  event: OpencodeEvent,
 66→): AgentTokenEvent | AgentFileChangeEvent | AgentStatusEvent {
 67→  switch (event.type) {
 68→    case "message.part.updated":
 69→      return {
 70→        type: "agent_token",
 71→        sessionId: event.sessionId,
 72→        token: event.part.content,
 73→      };
 74→
 75→    case "file.edited":
 76→      return {
 77→        type: "agent_file_change",
 78→        sessionId: event.sessionId,
 79→        file: event.file,
