/**
 * Coding Session Acceptance Test Kit
 *
 * Extends orchestrator-test-kit with coding-session-specific helpers.
 * Provides helpers for SSE event collection, prompt sending,
 * conversation log retrieval, and session state waiting.
 */
import type {
  OrchestratorTestRuntime,
  TestUser,
  AssignmentResponse,
} from "../coding-agent-orchestrator/orchestrator-test-kit";

// Re-export everything from the orchestrator test kit
export {
  setupOrchestratorSuite,
  createTestUser,
  createTestWorkspace,
  createReadyTask,
  assignTaskToAgent,
  getSessionStatus,
  acceptAgentWork,
  rejectWithFeedback,
  abortAgentSession,
  getReviewSummary,
  getTaskStatus,
  getAgentSessionsForTask,
  fetchJson,
  fetchRaw,
} from "../coding-agent-orchestrator/orchestrator-test-kit";

export type {
  OrchestratorTestRuntime,
  TestUser,
  TestWorkspace,
  TestTask,
  AssignmentResponse,
  SessionStatusResponse,
  ReviewResponse,
} from "../coding-agent-orchestrator/orchestrator-test-kit";

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type AgentStreamEvent = {
  type: string;
  sessionId?: string;
  token?: string;
  file?: string;
  changeType?: string;
  status?: string;
  error?: string;
  text?: string;
};

export type ConversationLogEntry = {
  entryType: "agent_text" | "file_change" | "user_prompt" | "status_change" | "stall_warning";
  timestamp: string;
  content?: string;
  file?: string;
  changeType?: string;
  status?: string;
};

export type ConversationLogResponse = {
  entries: ConversationLogEntry[];
};

export type PromptResponse = void;

// ---------------------------------------------------------------------------
// SSE Event Collection
// ---------------------------------------------------------------------------

/**
 * Subscribes to an agent session's SSE stream and collects events
 * until a terminal event or timeout.
 */
export async function collectSessionEvents(
  baseUrl: string,
  streamUrl: string,
  options: {
    timeoutMs?: number;
    stopOnTypes?: string[];
    maxEvents?: number;
  } = {},
): Promise<AgentStreamEvent[]> {
  const timeoutMs = options.timeoutMs ?? 15_000;
  const stopOnTypes = options.stopOnTypes ?? ["agent_done", "agent_error"];
  const maxEvents = options.maxEvents ?? 1000;

  const response = await fetch(`${baseUrl}${streamUrl}`, {
    headers: { Accept: "text/event-stream" },
  });

  if (!response.ok || !response.body) {
    throw new Error(`Failed to open session event stream (${response.status})`);
  }

  const reader = response.body.getReader();
  const decoder = new TextDecoder();
  const events: AgentStreamEvent[] = [];
  let buffer = "";

  const timeout = setTimeout(() => {
    void reader.cancel();
  }, timeoutMs);

  try {
    while (true) {
      const { value, done } = await reader.read();
      if (done) break;

      buffer += decoder.decode(value, { stream: true });
      const segments = buffer.split("\n\n");
      buffer = segments.pop() ?? "";

      for (const segment of segments) {
        const dataLine = segment
          .split("\n")
          .find((line) => line.startsWith("data: "));
        if (!dataLine) continue;

        const event = JSON.parse(
          dataLine.slice("data: ".length),
        ) as AgentStreamEvent;
        events.push(event);

        if (stopOnTypes.includes(event.type) || events.length >= maxEvents) {
          return events;
        }
      }
    }
  } finally {
    clearTimeout(timeout);
    reader.releaseLock();
  }

  return events;
}

// ---------------------------------------------------------------------------
// Follow-Up Prompt
// ---------------------------------------------------------------------------

/**
 * Sends a follow-up prompt to a running agent session.
 * Returns the raw Response for status code assertions.
 */
export async function sendFollowUpPrompt(
  baseUrl: string,
  user: TestUser,
  workspaceId: string,
  sessionId: string,
  text: string,
): Promise<Response> {
  return fetch(
    `${baseUrl}/api/orchestrator/${workspaceId}/sessions/${sessionId}/prompt`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json", ...user.headers },
      body: JSON.stringify({ text }),
    },
  );
}

// ---------------------------------------------------------------------------
// Conversation Log
// ---------------------------------------------------------------------------

/**
 * Retrieves the conversation log for a session (used in review).
 */
export async function getConversationLog(
  baseUrl: string,
  user: TestUser,
  workspaceId: string,
  sessionId: string,
): Promise<Response> {
  return fetch(
    `${baseUrl}/api/orchestrator/${workspaceId}/sessions/${sessionId}/log`,
    { headers: user.headers },
  );
}

// ---------------------------------------------------------------------------
// Session State Helpers
// ---------------------------------------------------------------------------

/**
 * Waits for a session to reach one of the target statuses.
 * Polls the session status endpoint at intervals.
 */
export async function waitForSessionStatus(
  baseUrl: string,
  user: TestUser,
  workspaceId: string,
  sessionId: string,
  targetStatuses: string[],
  options: { timeoutMs?: number; intervalMs?: number } = {},
): Promise<string> {
  const { getSessionStatus } = await import(
    "../coding-agent-orchestrator/orchestrator-test-kit"
  );
  const timeoutMs = options.timeoutMs ?? 30_000;
  const intervalMs = options.intervalMs ?? 500;
  const start = Date.now();

  while (Date.now() - start < timeoutMs) {
    const status = await getSessionStatus(
      baseUrl,
      user,
      workspaceId,
      sessionId,
    );
    if (targetStatuses.includes(status.orchestratorStatus)) {
      return status.orchestratorStatus;
    }
    await Bun.sleep(intervalMs);
  }

  throw new Error(
    `Session ${sessionId} did not reach status [${targetStatuses.join(", ")}] within ${timeoutMs}ms`,
  );
}

/**
 * Creates a full session setup: user, workspace, task, assignment.
 * Convenience for tests that need a running session as precondition.
 */
export async function createActiveSession(
  runtime: OrchestratorTestRuntime,
  suffix: string,
  taskTitle: string,
): Promise<{
  user: TestUser;
  workspaceId: string;
  assignment: AssignmentResponse;
  taskId: string;
}> {
  const {
    createTestUser,
    createTestWorkspace,
    createReadyTask,
    assignTaskToAgent,
  } = await import("../coding-agent-orchestrator/orchestrator-test-kit");

  const user = await createTestUser(runtime.baseUrl, suffix);
  const workspace = await createTestWorkspace(runtime.baseUrl, user);
  const task = await createReadyTask(runtime.surreal, workspace.workspaceId, {
    title: taskTitle,
  });
  const assignment = await assignTaskToAgent(
    runtime.baseUrl,
    user,
    workspace.workspaceId,
    task.taskId,
  );

  return {
    user,
    workspaceId: workspace.workspaceId,
    assignment,
    taskId: task.taskId,
  };
}

/**
 * Walking Skeleton: Live Coding Session E2E
 *
 * Traces: US-CS-003 (event stream wiring), US-CS-001 (live output),
 *         US-CS-002 (follow-up prompt), US-CS-004 (conversation log)
 *
 * These are the minimum viable E2E paths through the coding session feature.
 * A user assigns a task, observes the agent working in real-time, sends
 * follow-up instructions, and reviews the conversation log.
 *
 * Driving ports: POST /api/orchestrator/:ws/assign
 *                GET  /api/orchestrator/:ws/sessions/:id/stream (SSE)
 *                POST /api/orchestrator/:ws/sessions/:id/prompt
 *                GET  /api/orchestrator/:ws/sessions/:id/log
 *                GET  /api/orchestrator/:ws/sessions/:id/review
 */
import { describe, expect, it } from "bun:test";
import {
  setupOrchestratorSuite,
  createTestUser,
  createTestWorkspace,
  createReadyTask,
  assignTaskToAgent,
  getSessionStatus,
  collectSessionEvents,
  sendFollowUpPrompt,
  getConversationLog,
  getReviewSummary,
} from "./coding-session-test-kit";

const getRuntime = setupOrchestratorSuite("coding_session_skeleton");

describe("Walking Skeleton: Live coding session with agent interaction", () => {
  // ---------------------------------------------------------------------------
  // Walking Skeleton 1: Assign, observe output, send follow-up
  // US-CS-003 + US-CS-001 + US-CS-002
  // ---------------------------------------------------------------------------
  it("Marcus assigns a task, observes agent output, and sends a follow-up prompt", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a workspace with a project and a task ready for work
    const user = await createTestUser(baseUrl, "cs-skeleton-1");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Add form validation for email fields",
      description: "Validate email format on registration and login forms",
    });

    // When Marcus assigns the task to a coding agent
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
    );

    // Then the agent session starts and events begin streaming
    expect(assignment.agentSessionId).toBeTruthy();
    expect(assignment.streamUrl).toBeTruthy();

    const status = await getSessionStatus(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
    );
    expect(["spawning", "active"]).toContain(status.orchestratorStatus);

    // When Marcus opens the live output for the session
    // Then agent activity appears as streaming text
    // (With mocked OpenCode, verify the stream infrastructure is wired)
    const events = await collectSessionEvents(baseUrl, assignment.streamUrl, {
      timeoutMs: 5_000,
      maxEvents: 10,
    });
    // Stream should be connectable even if mock emits no events
    expect(events).toBeInstanceOf(Array);

    // When Marcus sends a follow-up prompt
    const promptResponse = await sendFollowUpPrompt(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
      "Please also add input validation",
    );

    // Then the prompt is accepted and the agent continues working
    expect(promptResponse.status).toBe(202);
  }, 60_000);

  // ---------------------------------------------------------------------------
  // Walking Skeleton 2: Review conversation log after completion
  // US-CS-003 + US-CS-004
  // ---------------------------------------------------------------------------
  it.skip("Marcus reviews the agent conversation log after work completes", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given Marcus has a task assigned to a coding agent that has completed
    const user = await createTestUser(baseUrl, "cs-skeleton-2");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Refactor authentication module",
    });
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
    );

    // When Marcus opens the review for the completed session
    const logResponse = await getConversationLog(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
    );

    // Then the review includes the agent conversation log
    expect(logResponse.ok).toBe(true);
    const log = (await logResponse.json()) as { entries: unknown[] };

    // And the log shows the chronological trail of agent activity
    expect(log.entries).toBeInstanceOf(Array);
  }, 60_000);

  // ---------------------------------------------------------------------------
  // Walking Skeleton 3: Agent error stops session
  // US-CS-001 + US-CS-003 (error path)
  // ---------------------------------------------------------------------------
  it.skip("agent error stops the session and notifies Marcus", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given Marcus has a task assigned to a coding agent
    const user = await createTestUser(baseUrl, "cs-skeleton-3");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Migrate legacy database schema",
    });
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
    );

    // When the agent encounters an error during its work
    // (With mocked OpenCode configured to emit error events)

    // Then the session status shows an error occurred
    const status = await getSessionStatus(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
    );
    expect(["error", "aborted"]).toContain(status.orchestratorStatus);

    // And Marcus is notified of the failure through the event stream
    const events = await collectSessionEvents(baseUrl, assignment.streamUrl, {
      timeoutMs: 10_000,
      stopOnTypes: ["agent_error"],
    });
    const errorEvents = events.filter((e) => e.type === "agent_error" || e.status === "error");
    expect(errorEvents.length).toBeGreaterThan(0);
  }, 60_000);
});

/**
 * Event Stream Wiring: Agent Events Flow to User via SSE
 *
 * Traces: US-CS-003 (wire event stream into session lifecycle)
 *
 * Validates that OpenCode events flow through event bridge to SSE registry
 * and reach the client's EventSource subscription. Also validates that
 * stall detection starts, terminal statuses stop iteration, and stream
 * errors update session status.
 *
 * Driving ports: POST /api/orchestrator/:ws/assign
 *                GET  /api/orchestrator/:ws/sessions/:id/stream (SSE)
 *                GET  /api/orchestrator/:ws/sessions/:id (status)
 */
import { describe, expect, it } from "bun:test";
import {
  setupOrchestratorSuite,
  createTestUser,
  createTestWorkspace,
  createReadyTask,
  assignTaskToAgent,
  getSessionStatus,
  abortAgentSession,
  acceptAgentWork,
  collectSessionEvents,
  fetchRaw,
} from "./coding-session-test-kit";

const getRuntime = setupOrchestratorSuite("event_stream_wiring");

describe("Event Stream Wiring: Agent events flow to user", () => {
  // ---------------------------------------------------------------------------
  // Happy Path: Events appear in the session stream
  // US-CS-003 AC: eventStream iterated after spawn
  // ---------------------------------------------------------------------------
  it.skip("agent events flow through to the session event stream", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a workspace with a task assigned to a coding agent
    const user = await createTestUser(baseUrl, "wire-events");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Build search results component",
    });
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
    );

    // When the agent produces activity events
    // Then the events appear in the session's live stream
    const events = await collectSessionEvents(baseUrl, assignment.streamUrl, {
      timeoutMs: 10_000,
    });

    expect(events.length).toBeGreaterThan(0);
  }, 30_000);

  // ---------------------------------------------------------------------------
  // Happy Path: Session transitions to active after first event
  // US-CS-003 AC: session status -> "active" after first agent event
  // ---------------------------------------------------------------------------
  it.skip("session transitions to active after first agent event", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a session in "spawning" status
    const user = await createTestUser(baseUrl, "wire-active");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Implement pagination controls",
    });
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
    );

    // When the first agent event arrives
    // (Wait briefly for event processing)
    await Bun.sleep(2_000);

    // Then the session status transitions to "active"
    const status = await getSessionStatus(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
    );
    expect(status.orchestratorStatus).toBe("active");
  }, 30_000);

  // ---------------------------------------------------------------------------
  // Happy Path: Stall detection starts after wiring
  // US-CS-003 AC: stall detector starts after event bridge wired
  // ---------------------------------------------------------------------------
  it.skip("stall monitoring begins after agent session starts", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a task assigned to an agent
    const user = await createTestUser(baseUrl, "wire-stall");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Add loading spinner component",
    });
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
    );

    // When the event stream is wired to the session
    // Then stall detection monitoring is active
    // (Verified by: if no events arrive within stall timeout, session aborts)
    // With short stall timeout configured for tests, wait for stall detection
    await Bun.sleep(12_000);

    const status = await getSessionStatus(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
    );
    // Stall detector should have fired (mock OpenCode emits no events)
    expect(["aborted", "error"]).toContain(status.orchestratorStatus);
  }, 30_000);
});

describe("Event Stream Wiring: Error and terminal status handling", () => {
  // ---------------------------------------------------------------------------
  // Error Path: Stream error updates session status
  // US-CS-003 AC: event stream errors -> session status "error"
  // ---------------------------------------------------------------------------
  it.skip("event stream error updates session to error status", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a task assigned to an agent whose stream encounters an error
    const user = await createTestUser(baseUrl, "wire-error");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Integrate payment gateway",
    });
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
    );

    // When the agent's event stream encounters an error
    // (Mock OpenCode configured to emit error after delay)
    await Bun.sleep(5_000);

    // Then the session status changes to "error"
    const status = await getSessionStatus(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
    );
    expect(["error", "aborted"]).toContain(status.orchestratorStatus);

    // And an error event is emitted to the live stream
    const events = await collectSessionEvents(baseUrl, assignment.streamUrl, {
      timeoutMs: 5_000,
      stopOnTypes: ["agent_error"],
    });
    const errorEvents = events.filter(
      (e) => e.type === "agent_error" || e.type === "agent_status",
    );
    expect(errorEvents.length).toBeGreaterThanOrEqual(0);
  }, 30_000);

  // ---------------------------------------------------------------------------
  // Error Path: Event iteration stops on completed status
  // US-CS-003 AC: iteration stops on terminal status
  // ---------------------------------------------------------------------------
  it.skip("event iteration stops when session reaches completed status", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a task assigned to an agent
    const user = await createTestUser(baseUrl, "wire-complete");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Create user profile page",
    });
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
    );

    // When the session is completed (accept the work)
    await acceptAgentWork(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
    );

    // Then no further events are processed from the agent stream
    const status = await getSessionStatus(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
    );
    expect(status.orchestratorStatus).toBe("completed");
  }, 60_000);

  // ---------------------------------------------------------------------------
  // Error Path: Event iteration stops on aborted status
  // US-CS-003 AC: iteration stops on terminal status
  // ---------------------------------------------------------------------------
  it.skip("event iteration stops when session is aborted", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a task assigned to an agent
    const user = await createTestUser(baseUrl, "wire-abort");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Build notification system",
    });
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
    );

    // When the session is aborted by the user
    await abortAgentSession(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
    );

    // Then no further events are processed from the agent stream
    const status = await getSessionStatus(
      baseUrl,
      user,
      workspace.workspaceId,
      assignment.agentSessionId,
    );
    expect(status.orchestratorStatus).toBe("aborted");
  }, 60_000);

  // ---------------------------------------------------------------------------
  // Edge Case: Nonexistent stream subscription
  // ---------------------------------------------------------------------------
  it.skip("subscribing to a nonexistent session stream fails", async () => {
    const { baseUrl } = getRuntime();

    // Given a stream identifier that does not correspond to any session
    // When a user tries to subscribe to that stream
    const response = await fetchRaw(
      `${baseUrl}/api/orchestrator/stream/nonexistent-stream-id`,
      { headers: { Accept: "text/event-stream" } },
    );

    // Then the subscription is rejected because no matching session exists
    expect(response.ok).toBe(false);
  }, 15_000);
});

/**
 * Live Agent Output: Streaming Text, File Changes, Status Updates
 *
 * Traces: US-CS-001 (live agent output stream)
 *
 * Validates that agent token events stream as text, file changes appear
 * as inline notifications, status transitions update in real-time,
 * file change counts update, and stall warnings appear on inactivity.
 *
 * Driving ports: POST /api/orchestrator/:ws/assign
 *                GET  /api/orchestrator/:ws/sessions/:id/stream (SSE)
 *                GET  /api/orchestrator/:ws/sessions/:id (status)
 */
import { describe, expect, it } from "bun:test";
import {
  setupOrchestratorSuite,
  createTestUser,
  createTestWorkspace,
  createReadyTask,
  assignTaskToAgent,
  getSessionStatus,
  collectSessionEvents,
} from "./coding-session-test-kit";

const getRuntime = setupOrchestratorSuite("live_agent_output");

describe("Live Agent Output: Token and file change streaming", () => {
  // ---------------------------------------------------------------------------
  // Happy Path: Token events render as streaming text
  // US-CS-001 AC: agent token events stream into output panel
  // ---------------------------------------------------------------------------
  it.skip("agent token events render as streaming text", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a task assigned to a coding agent
    const user = await createTestUser(baseUrl, "output-tokens");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Generate API documentation",
    });
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
    );

    // When the agent produces text output
    const events = await collectSessionEvents(baseUrl, assignment.streamUrl, {
      timeoutMs: 10_000,
    });

    // Then the output appears as streaming text in the session stream
    const tokenEvents = events.filter((e) => e.type === "agent_token");
    expect(tokenEvents.length).toBeGreaterThan(0);
    for (const event of tokenEvents) {
      expect(typeof event.token).toBe("string");
    }
  }, 30_000);

  // ---------------------------------------------------------------------------
  // Happy Path: File change events as inline notifications
  // US-CS-001 AC: file change events appear as distinct inline notifications
  // ---------------------------------------------------------------------------
  it.skip("file change events appear as inline notifications", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a task assigned to a coding agent
    const user = await createTestUser(baseUrl, "output-files");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Create authentication middleware",
    });
    const assignment = await assignTaskToAgent(
      baseUrl,
      user,
      workspace.workspaceId,
      task.taskId,
